import { getAllAccounts, createAccount, updateAccount, deleteAccount } from '../api/Account.js';
import { getAllSubjects, createSubject, updateSubject, deleteSubject } from '../api/Subject.js';
import { getAllQAs, createQA, updateQA, deleteQA } from '../api/QA.js';
import { getAllExams, createExam, updateExam, deleteExam } from '../api/Exam.js';
import { checkAIHealth, getAllAIRequests } from '../api/AI.js';
import '../styles/page-backgrounds.css';
export default {
  name: 'Admin',
  data() {
    return {
      currentUser: {
        username: 'admin',
        role: 'admin'
      },
      activeTab: 'users',
      searchQuery: '',
      subjectSearchQuery: '',
      questionSearchQuery: '',
      examSearchQuery: '',
      loading: false,
      showEditModal: false,
      showCreateUserModal: false,
      showCreateSubjectModal: false,
      showCreateQuestionModal: false,
      showCreateExamModal: false,
      showAIConfigModal: false,
      users: [],
      subjects: [],
      questions: [],
      exams: [],
      aiRequests: [],
      editingUser: {},
      editingSubject: {},
      editingQuestion: {},
      editingExam: {},
      newUser: {
        username: '',
        email: '',
        password: '',
        role: 'user'
      },
      newSubject: {
        name: '',
        category: '',
        difficulty: 'easy',
        featured: false
      },
      newQuestion: {
        question: '',
        subjectId: '',
        levelId: 1,
        type: 'multiple-choice',
        options: ['', '', '', ''],
        correctAnswer: 0
      },
      newExam: {
        title: '',
        subjectId: '',
        difficulty: 'easy',
        duration: 60,
        questions: []
      },
      aiHealth: {
        status: 'unknown',
        responseTime: 0,
        lastCheck: new Date(),
        uptime: '0%'
      },
      aiConfig: {
        model: 'gpt-3.5-turbo',
        maxTokens: 1000,
        temperature: 0.7
      },
      tabs: [{
        id: 'users',
        name: 'Users',
        icon: 'fas fa-users'
      }, {
        id: 'subjects',
        name: 'Subjects',
        icon: 'fas fa-book'
      }, {
        id: 'questions',
        name: 'Questions',
        icon: 'fas fa-question-circle'
      }, {
        id: 'exams',
        name: 'Exams',
        icon: 'fas fa-clipboard-list'
      }, {
        id: 'ai',
        name: 'AI Health',
        icon: 'fas fa-robot'
      }, {
        id: 'stats',
        name: 'Statistics',
        icon: 'fas fa-chart-bar'
      }, {
        id: 'system',
        name: 'System',
        icon: 'fas fa-cog'
      }],
      stats: {
        totalUsers: 0,
        totalAdmins: 0,
        avgLevel: 0,
        avgStreak: 0
      }
    };
  },
  computed: {
    filteredUsers() {
      if (!this.searchQuery) return this.users;
      return this.users.filter(user => user.username.toLowerCase().includes(this.searchQuery.toLowerCase()) || user.email.toLowerCase().includes(this.searchQuery.toLowerCase()));
    },
    filteredSubjects() {
      if (!this.subjectSearchQuery) return this.subjects;
      return this.subjects.filter(subject => subject.name.toLowerCase().includes(this.subjectSearchQuery.toLowerCase()) || subject.category.toLowerCase().includes(this.subjectSearchQuery.toLowerCase()));
    },
    filteredQuestions() {
      if (!this.questionSearchQuery) return this.questions;
      return this.questions.filter(question => question.question.toLowerCase().includes(this.questionSearchQuery.toLowerCase()));
    },
    filteredExams() {
      if (!this.examSearchQuery) return this.exams;
      return this.exams.filter(exam => exam.title.toLowerCase().includes(this.examSearchQuery.toLowerCase()));
    },
    recentAIRequests() {
      return this.aiRequests.slice(0, 10);
    }
  },
  async mounted() {
    await this.checkAdminAccess();
    await this.loadAllData();
    this.calculateStats();
  },
  methods: {
    async checkAdminAccess() {
      const token = localStorage.getItem('token');
      if (!token) {
        this.$router.push('/login');
        return;
      }
      try {
        // Decode token to get user info
        const payload = JSON.parse(atob(token.split('.')[1]));
        this.currentUser.username = payload.username;

        // Check if user is admin
        if (payload.role !== 'admin') {
          this.$router.push('/dashboard');
          return;
        }
      } catch (error) {
        console.error('Token validation error:', error);
        this.$router.push('/login');
      }
    },
    async loadAllData() {
      this.loading = true;
      try {
        await Promise.all([this.loadUsers(), this.loadSubjects(), this.loadQuestions(), this.loadExams(), this.loadAIRequests(), this.checkAIHealth()]);
      } catch (error) {
        console.error('Error loading data:', error);
      } finally {
        this.loading = false;
      }
    },
    async loadUsers() {
      try {
        const response = await getAllAccounts();
        this.users = response.data || [];
      } catch (error) {
        console.error('Error loading users:', error);
        alert('Failed to load users');
      }
    },
    async loadSubjects() {
      try {
        const response = await getAllSubjects();
        this.subjects = response.data || [];
      } catch (error) {
        console.error('Error loading subjects:', error);
      }
    },
    async loadQuestions() {
      try {
        const response = await getAllQAs();
        this.questions = response.data || [];
      } catch (error) {
        console.error('Error loading questions:', error);
      }
    },
    async loadExams() {
      try {
        const response = await getAllExams();
        this.exams = response.data || [];
      } catch (error) {
        console.error('Error loading exams:', error);
      }
    },
    async loadAIRequests() {
      try {
        const response = await getAllAIRequests();
        this.aiRequests = response.data || [];
      } catch (error) {
        console.error('Error loading AI requests:', error);
      }
    },
    calculateStats() {
      this.stats.totalUsers = this.users.filter(u => u.role === 'user').length;
      this.stats.totalAdmins = this.users.filter(u => u.role === 'admin').length;
      if (this.users.length > 0) {
        this.stats.avgLevel = Math.round(this.users.reduce((sum, u) => sum + u.currentLevel, 0) / this.users.length);
        this.stats.avgStreak = Math.round(this.users.reduce((sum, u) => sum + u.streak, 0) / this.users.length);
      }
    },
    editUser(user) {
      this.editingUser = {
        ...user
      };
      this.showEditModal = true;
    },
    closeEditModal() {
      this.showEditModal = false;
      this.editingUser = {};
    },
    async saveUser() {
      try {
        await updateAccount(this.editingUser._id, this.editingUser);
        await this.loadUsers();
        this.calculateStats();
        this.closeEditModal();
        alert('User updated successfully');
      } catch (error) {
        console.error('Error updating user:', error);
        alert('Failed to update user');
      }
    },
    async deleteUser(userId) {
      if (!confirm('Are you sure you want to delete this user?')) return;
      try {
        await deleteAccount(userId);
        await this.loadUsers();
        this.calculateStats();
        alert('User deleted successfully');
      } catch (error) {
        console.error('Error deleting user:', error);
        alert('Failed to delete user');
      }
    },
    formatDate(dateString) {
      return new Date(dateString).toLocaleDateString();
    },
    logout() {
      localStorage.removeItem('token');
      this.$router.push('/login');
    }
  }
};
